parameters.jsCode:
// Decide which touch to send next
const items = [];
for (const it of $input.all()) {
  const lead = it.json;
  let nextTouch = 2;
  if (lead.stage === 'sent_t2') nextTouch = 3;
  else if (lead.stage === 'sent_t3') nextTouch = 4;
  let seq = lead.sequence;
  if (typeof seq === 'string') { try { seq = JSON.parse(seq); } catch(e){ seq={}; } }
  const body = seq['email_'+nextTouch] || '';
  const subject = 'Re: ' + (seq.subject_a || 'following up');
  items.push({ json: { ...lead, next_touch: nextTouch, send_subject: subject, send_body: body } });
}
return items;
